class Solution:
    def maxSum(self, nums: List[int], k: int) -> int:
        MOD = 10**9 + 7
        bit_count = [0] * 32  # To count the number of set bits for each position

        # Count the number of set bits for each bit position
        for num in nums:
            for i in range(32):
                if num & (1 << i):
                    bit_count[i] += 1

        # Maximize the top k elements by concentrating bits
        result = 0
        for _ in range(k):
            val = 0
            for i in range(32):
                if bit_count[i] > 0:
                    val |= (1 << i)
                    bit_count[i] -= 1
            result = (result + val * val) % MOD

        return result
